import{e as t,m as e}from"./chunks/theme.C9g6HaIV.js";import{c as o,Q as r,j as s,m as n}from"./chunks/framework.BPKcPtvA.js";const b=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/portal/dashboard.md","filePath":"guide/portal/dashboard.md","lastUpdated":1778912818000}'),i={name:"guide/portal/dashboard.md"};function l(d,a,h,u,c,g){return r(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>The Customer Portal Dashboard is your operational summary. It shows the health of your tenants, your account metadata, and quick navigation into the parts of the portal you use most.</p><p><img src="'+t+'" alt="Customer Portal Dashboard" class="light-only"><img src="'+e+'" alt="Customer Portal Dashboard" class="dark-only"></p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li>A welcome header with your customer&#39;s name.</li><li>Three metric cards: <ul><li><strong>Tenants</strong> — number of tenants you own.</li><li><strong>Portal Users</strong> — number of users with access to your portal.</li><li><strong>Bound Instances</strong> — number of hosted instances that run your tenants.</li></ul></li><li>An <strong>Account Details</strong> card with Plan, Status, Billing Contact, and Timezone.</li><li>A <strong>Tenant Insights</strong> grid — one card per tenant with key usage metrics and status.</li></ul><h2 id="tenant-insight-card" tabindex="-1">Tenant insight card <a class="header-anchor" href="#tenant-insight-card" aria-label="Permalink to &quot;Tenant insight card&quot;">​</a></h2><p>Each tenant card shows:</p><ul><li><strong>Name</strong> with environment badge (PROD / DEV / QA …).</li><li><strong>MAU</strong> (Monthly Active Users), <strong>Avg DAU</strong> (Daily Active Users), <strong>Workflows</strong> executed, <strong>Error Rate</strong> percentage.</li><li>A <strong>status indicator</strong> (active / suspended / archived).</li><li>A 30-day indicator at the bottom.</li></ul><p>Cards are colour-coded by error rate:</p><ul><li>Green — error rate under 1%.</li><li>Red — error rate at or above 1%, or tenant status is suspended.</li></ul><p>Click any card to jump to the tenant&#39;s full detail page.</p><p>The <strong>View all</strong> link in the section header takes you to <a href="./tenants">Tenants</a>.</p><h2 id="what-this-page-is-good-for" tabindex="-1">What this page is good for <a class="header-anchor" href="#what-this-page-is-good-for" aria-label="Permalink to &quot;What this page is good for&quot;">​</a></h2><ul><li>A morning check to confirm everything is healthy.</li><li>Spotting a tenant whose error rate has spiked.</li><li>Confirming your portal user count and plan are what you expect.</li></ul><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>This page requires the <code>view_dashboard</code> portal action. If your role does not have it, you will not see the Dashboard in the sidebar — your home page becomes the next available page.</p>',16)])])}const f=o(i,[["render",l]]);export{b as __pageData,f as default};
